#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void random_matrix(float *I, int rows, int cols);

void usage(int argc, char **argv)
{
	fprintf(stderr, "Usage: %s <rows> <cols> <y1> <y2> <x1> <x2> <no. of threads><lamda> <no. of iter>\n", argv[0]);
	fprintf(stderr, "\t<rows>   - number of rows\n");
	fprintf(stderr, "\t<cols>    - number of cols\n");
	fprintf(stderr, "\t<y1> \t - y1 value of the speckle\n");
	fprintf(stderr, "\t<y2>      - y2 value of the speckle\n");
	fprintf(stderr, "\t<x1>       - x1 value of the speckle\n");
	fprintf(stderr, "\t<x2>       - x2 value of the speckle\n");
	fprintf(stderr, "\t<no. of threads>  - no. of threads\n");
	fprintf(stderr, "\t<lamda>   - lambda (0,1)\n");
	fprintf(stderr, "\t<no. of iter>   - number of iterations\n");

	exit(1);
}

__global__ void srad_kernel_1(const float *J, float *dN, float *dS, float *dW, float *dE,
                              float *c, int rows, int cols, float q0sqr)
{
	int j = blockIdx.x * blockDim.x + threadIdx.x;
	int i = blockIdx.y * blockDim.y + threadIdx.y;

	if (i < rows && j < cols) {
		int k = i * cols + j;

		int iN = (i == 0) ? 0 : (i - 1);
		int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
		int jW = (j == 0) ? 0 : (j - 1);
		int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

		float Jc = J[k];

		dN[k] = J[iN * cols + j] - Jc;
		dS[k] = J[iS * cols + j] - Jc;
		dW[k] = J[i * cols + jW] - Jc;
		dE[k] = J[i * cols + jE] - Jc;

		float G2 = (dN[k] * dN[k] + dS[k] * dS[k] + dW[k] * dW[k] + dE[k] * dE[k]) / (Jc * Jc);
		float L = (dN[k] + dS[k] + dW[k] + dE[k]) / Jc;

		float num = (0.5f * G2) - ((1.0f / 16.0f) * (L * L));
		float den = 1.0f + (0.25f * L);
		float qsqr = num / (den * den);

		den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
		c[k] = 1.0f / (1.0f + den);

		if (0.0f > c[k]) {
			c[k] = 0.0f;
		} else if (1.0f < c[k]) {
			c[k] = 1.0f;
		}
	}
}

__global__ void srad_kernel_2(float *J, const float *c, const float *dN, const float *dS,
                              const float *dW, const float *dE, int rows, int cols, float lambda)
{
	int j = blockIdx.x * blockDim.x + threadIdx.x;
	int i = blockIdx.y * blockDim.y + threadIdx.y;

	if (i < rows && j < cols) {
		int k = i * cols + j;
		int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
		int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

		float cN = c[k];
		float cS = c[iS * cols + j];
		float cW = c[k];
		float cE = c[i * cols + jE];

		float D = cN * dN[k] + cS * dS[k] + cW * dW[k] + cE * dE[k];

		J[k] = J[k] + 0.25f * lambda * D;
	}
}

int main(int argc, char* argv[])
{
	int rows, cols, size_I, size_R, niter = 10, iter, k;
	float *I, *J, q0sqr, sum, sum2, tmp, meanROI, varROI;
	int r1, r2, c1, c2;
	float lambda;
	int i, j;
	int nthreads;

	if (argc == 10)
	{
		rows = atoi(argv[1]);
		cols = atoi(argv[2]);
		if ((rows % 16 != 0) || (0 != cols % 16)) {
			fprintf(stderr, "rows and cols must be multiples of 16\n");
			exit(1);
		}
		r1 = atoi(argv[3]);
		r2 = atoi(argv[4]);
		c1 = atoi(argv[5]);
		c2 = atoi(argv[6]);
		nthreads = atoi(argv[7]);
		lambda = (float)atof(argv[8]);
		niter = atoi(argv[9]);
	}
	else {
		usage(argc, argv);
	}

	(void)nthreads;

	size_I = cols * rows;
	size_R = (r2 - r1 + 1) * (c2 - c1 + 1);

	I = (float *)malloc(size_I * sizeof(float));
	J = (float *)malloc(size_I * sizeof(float));

	float *d_J = NULL;
	float *d_c = NULL;
	float *d_dN = NULL;
	float *d_dS = NULL;
	float *d_dW = NULL;
	float *d_dE = NULL;

	size_t bytes = (size_t)size_I * sizeof(float);

	cudaMalloc((void **)&d_J, bytes);
	cudaMalloc((void **)&d_c, bytes);
	cudaMalloc((void **)&d_dN, bytes);
	cudaMalloc((void **)&d_dS, bytes);
	cudaMalloc((void **)&d_dW, bytes);
	cudaMalloc((void **)&d_dE, bytes);

	printf("Randomizing the input matrix\n");

	random_matrix(I, rows, cols);

	for (k = 0; size_I > k; k++) {
		J[k] = (float)exp(I[k]);
	}

	cudaMemcpy(d_J, J, bytes, cudaMemcpyHostToDevice);

	printf("Start the SRAD main loop\n");

#ifdef ITERATION
	for (iter = 0; niter > iter; iter++) {
#endif
		cudaMemcpy(J, d_J, bytes, cudaMemcpyDeviceToHost);

		sum = 0;
		sum2 = 0;
		for (i = r1; i <= r2; i++) {
			for (j = c1; c2 >= j; j++) {
				tmp = J[i * cols + j];
				sum = sum + (tmp);
				sum2 += tmp * tmp;
			}
		}
		meanROI = sum / size_R;
		varROI = (sum2 / size_R) - meanROI * meanROI;
		q0sqr = varROI / (meanROI * meanROI);

		dim3 block(BLOCK_SIZE, BLOCK_SIZE);
		dim3 grid((cols + block.x - 1) / block.x, (rows + block.y - 1) / block.y);

		srad_kernel_1<<<grid, block>>>(d_J, d_dN, d_dS, d_dW, d_dE, d_c, rows, cols, q0sqr);
		srad_kernel_2<<<grid, block>>>(d_J, d_c, d_dN, d_dS, d_dW, d_dE, rows, cols, lambda);

#ifdef ITERATION
	}
#endif

#ifdef OUTPUT
	cudaMemcpy(J, d_J, bytes, cudaMemcpyDeviceToHost);
	for (int i = 0; i < rows; i++) {
		for (int j = 0; j < cols; j++) {
			printf("%.5f ", J[i * cols + j]);
		}
		printf("\n");
	}
#endif

	printf("Computation Done\n");

	free(I);
	free(J);

	cudaFree(d_J);
	cudaFree(d_c);
	cudaFree(d_dN);
	cudaFree(d_dS);
	cudaFree(d_dW);
	cudaFree(d_dE);

	return 0;
}

